import{_ as t,o as a,c as o,a0 as i}from"./chunks/framework.BjpW4enL.js";const m=JSON.parse('{"title":"ADR: Forgetful Swarm Dynamics (The \\"Bubble\\" Hypothesis)","description":"","frontmatter":{},"headers":[],"relativePath":"20_Arquitetura/adr/0021-forgetful-swarm-dynamics.md","filePath":"20_Arquitetura/adr/0021-forgetful-swarm-dynamics.md","lastUpdated":1783623176000}'),s={name:"20_Arquitetura/adr/0021-forgetful-swarm-dynamics.md"};function r(n,e,l,c,h,d){return a(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="adr-forgetful-swarm-dynamics-the-bubble-hypothesis" tabindex="-1">ADR: Forgetful Swarm Dynamics (The &quot;Bubble&quot; Hypothesis) <a class="header-anchor" href="#adr-forgetful-swarm-dynamics-the-bubble-hypothesis" aria-label="Permalink to &quot;ADR: Forgetful Swarm Dynamics (The &quot;Bubble&quot; Hypothesis)&quot;">​</a></h1><h2 id="context" tabindex="-1">Context <a class="header-anchor" href="#context" aria-label="Permalink to &quot;Context&quot;">​</a></h2><p>Entities (agents/blobs) that cluster but constantly generate &#39;conflict signals&#39; (high drift, low stability) effectively create entropic bubbles that drain the pipeline. We need a formal mechanism for &#39;forgetting&#39; these associations to allow the swarm to stabilize into islands of coherent activity.</p><h2 id="the-forgetfulness-protocol" tabindex="-1">The Forgetfulness Protocol <a class="header-anchor" href="#the-forgetfulness-protocol" aria-label="Permalink to &quot;The Forgetfulness Protocol&quot;">​</a></h2><ol><li><strong>Isolation Islands</strong>: When a triad of nodes (Agent A, Agent B, Context C) exhibits persistent entropic drift &gt; 0.6 over 3 consecutive enrichment cycles, the association is marked as a &#39;Conflict Island&#39;.</li><li><strong>Forgetting Mechanism</strong>: Instead of deleting, we apply a &#39;Stigmergic Decay&#39; to the relationship links. The weight of the association decays linearly until it falls below the enrichment threshold (causing it to disappear from the L2/L3 synthesis view).</li><li><strong>Emergence</strong>: This allows for &#39;vices&#39; (stable conflict cycles) to be visualized as distinct &#39;islands&#39; in the graph, which can then be synthesized by higher-order L3 agents as distinct behavioral archetypes.</li></ol><h2 id="implementation-path" tabindex="-1">Implementation Path <a class="header-anchor" href="#implementation-path" aria-label="Permalink to &quot;Implementation Path&quot;">​</a></h2><ul><li><strong>Schema Update</strong>: Add <code>decay_score</code> to the <code>links</code> table in the database.</li><li><strong>Agent Policy</strong>: Implement a worker agent responsible for the <code>DecayRoutine</code> (running during low-resource periods).</li></ul>',7)])])}const f=t(s,[["render",r]]);export{m as __pageData,f as default};
